```{.r .cell-code}
# グローバル状態列に基づく経験的な遷移頻度
df_hmm_decoded |>
  mutate(next_state = dplyr::lead(state_global)) |>
  filter(!is.na(next_state)) |>
  count(state_global, next_state, name = "n") |>
  group_by(state_global) |>
  mutate(prob = n / sum(n)) |>
  ungroup() |>
  gt() |>
  tab_header(title = "Decoded state transitions (empirical proportions)") |>
  fmt_number(columns = prob, decimals = 3)
```

